// FIX: convert exp to milliseconds
if (Date.now() >= token.exp * 1000) { ... }
```

Or use JWT library's built-in check — catches it for you and validates signature too:

```javascript
const jwt = require('jsonwebtoken');

const auth = (req, res, next) => {
  const token = req.headers.authorization?.split(' ')[1];

  try {
    req.user = jwt.verify(token, process.env.JWT_SECRET);
    next();
  } catch (err) {
    return res.status(401).json({ message: 'Token invalid or expired' });
  }
};
```

`jwt.verify()` handles expiry, signature, and malformed tokens. Manual timestamp compare only needed if using a stripped library.

