# PostgreSQL Connection Pool in Node.js

Here's a comprehensive setup with proper configuration, timeouts, and error handling:

## Basic Setup with `pg` Library

```javascript
// db.js
const { Pool } = require('pg');

// Configuration object
const dbConfig = {
  host: process.env.DB_HOST || 'localhost',
  port: process.env.DB_PORT || 5432,
  database: process.env.DB_NAME || 'myapp',
  user: process.env.DB_USER || 'postgres',
  password: process.env.DB_PASSWORD,

  // Pool settings
  max: 20,                    // Maximum connections in pool
  idleTimeoutMillis: 30000,   // Close idle connections after 30s
  connectionTimeoutMillis: 5000, // Return error after 5s if can't connect

  // Statement timeout (per-query)
  statement_timeout: 30000,   // 30 second query timeout

  // Keep alive to prevent dropped connections
  keepAlive: true,
  keepAliveInitialDelayMillis: 10000,
};

const pool = new Pool(dbConfig);

// --- Event Handlers ---

pool.on('error', (err, client) => {
  console.error('Unexpected error on idle client:', err);
  // Don't exit process in production - log and monitor instead
});

pool.on('connect', () => {
  console.log('New client connected to PostgreSQL');
});

pool.on('remove', () => {
  console.log('Client removed from pool');
});

