## Advanced Error Handling Wrapper

```javascript
// db-wrapper.js
const pool = require('./db');

class DatabaseError extends Error {
  constructor(message, originalError, query) {
    super(message);
    this.name = 'DatabaseError';
    this.originalError = originalError;
    this.query = query;
  }
}

class QueryTimeoutError extends Error {
  constructor(message, timeout) {
    super(message);
    this.name = 'QueryTimeoutError';
    this.timeout = timeout;
  }
}

// Timeout-aware query wrapper
const queryWithTimeout = async (text, params, timeoutMs = 30000) => {
  const timeout = new Promise((_, reject) => {
    setTimeout(() => {
      reject(new QueryTimeoutError(
        `Query timeout after ${timeoutMs}ms`,
        timeoutMs
      ));
    }, timeoutMs);
  });

  try {
    const result = await Promise.race([
      pool.query(text, params),
      timeout
    ]);
    return result;
  } catch (error) {
    if (error instanceof QueryTimeoutError) {
      throw error;
    }

    // Handle specific PostgreSQL errors
    if (error.code) {
      const errorMessages = {
        '23505': 'Unique constraint violation',
        '23503': 'Foreign key violation',
        '23502': 'Not null violation',
        '42P01': 'Table does not exist',
        '08006': 'Connection lost',
        'ECONNREFUSED': 'Database connection refused',
        'ETIMEDOUT': 'Connection timed out',
      };

      const friendlyMessage = errorMessages[error.code] || errorMessages[error.errno] || 'Database error';
      throw new DatabaseError(friendlyMessage, error, { text, params });
    }

    throw error;
  }
};

// Transaction helper with automatic retry
const withTransaction = async (callback, maxRetries = 3) => {
  let retries = 0;

  while (retries < maxRetries) {
    const client = await pool.connect();

    try {
      await client.query('BEGIN');
      const result = await callback(client);
      await client.query('COMMIT');
      return result;
    } catch (error) {
      await client.query('ROLLBACK');

      // Retry on transient errors
      if (isRetryableError(error) && retries < maxRetries - 1) {
        retries++;
        const delay = Math.min(100 * Math.pow(2, retries), 2000);
        await sleep(delay);
        continue;
      }
      throw error;
    } finally {
      client.release();
    }
  }
};

const isRetryableError = (error) => {
  // Connection errors, deadlocks, serialization failures
  const retryableCodes = [
    '08000', // connection exception
    '08003', // connection does not exist
    '08006', // connection failure
    '40001', // serialization failure
    '40P01', // deadlock
    'ECONNRESET',
    'ECONNREFUSED',
    'ETIMEDOUT'
  ];
  return retryableCodes.includes(error.code) || 
         retryableCodes.includes(error.errno);
};

const sleep = (ms) => new Promise(resolve => setTimeout(resolve, ms));

module.exports = {
  query: queryWithTimeout,
  withTransaction,
  pool,
  DatabaseError,
  QueryTimeoutError
};
```

