```javascript
// db.js
const { Pool } = require('pg');

class DatabasePool {
  constructor() {
    this.pool = new Pool({
      host: process.env.DB_HOST || 'localhost',
      port: process.env.DB_PORT || 5432,
      database: process.env.DB_NAME || 'myapp',
      user: process.env.DB_USER || 'postgres',
      password: process.env.DB_PASSWORD,

      // Pool configuration
      max: 20,
      min: 2,
      idleTimeoutMillis: 30000,
      connectionTimeoutMillis: 5000,

      // Statement timeout (per-query) - returns error after 30s
      statement_timeout: 30000,

      // Allow exit on idle (for graceful shutdown)
      allowExitOnIdle: true
    });

    this.setupEventHandlers();
  }

  setupEventHandlers() {
    // Handle connection errors
    this.pool.on('error', (err, client) => {
      console.error('Unexpected error on idle client:', err);
      // Don't exit - let pool handle reconnection
    });

    // Connection established
    this.pool.on('connect', () => {
      console.log('New client connected to PostgreSQL');
    });

    // Pool error
    this.pool.on('error', (err) => {
      console.error('Pool error:', err);
    });
  }

  // Execute a query with timeout wrapper
  async query(text, params, timeoutMs = 30000) {
    const start = Date.now();

    const timeoutPromise = new Promise((_, reject) => {
      setTimeout(() => reject(new Error(`Query timeout after ${timeoutMs}ms`)), timeoutMs);
    });

    try {
      const result = await Promise.race([
        this.pool.query(text, params),
        timeoutPromise
      ]);

      const duration = Date.now() - start;
      console.log('Query executed', { text, duration, rows: result.rowCount });

      return result;
    } catch (error) {
      console.error('Query error:', { text, error: error.message });
      throw error;
    }
  }

  // Get a client for transactions
  async getClient() {
    const client = await this.pool.connect();
    const originalQuery = client.query.bind(client);
    const release = client.release.bind(client);

    // Override release to handle double-release
    client.release = () => {
      client.query = originalQuery;
      client.release = release;
      return release();
    };

    return client;
  }

  // Transaction helper
  async transaction(callback) {
    const client = await this.getClient();

    try {
      await client.query('BEGIN');
      const result = await callback(client);
      await client.query('COMMIT');
      return result;
    } catch (error) {
      await client.query('ROLLBACK');
      throw error;
    } finally {
      client.release();
    }
  }

  // Health check
  async healthCheck() {
    try {
      const result = await this.pool.query('SELECT NOW()');
      return { healthy: true, timestamp: result.rows[0].now };
    } catch (error) {
      return { healthy: false, error: error.message };
    }
  }

  // Graceful shutdown
  async close() {
    console.log('Closing database pool...');
    await this.pool.end();
    console.log('Pool has ended');
  }
}

module.exports = new DatabasePool();
