const { Pool } = require('pg');

class Database {
  constructor() {
    this.pool = null;
    this.isShuttingDown = false;
  }

  initialize() {
    this.pool = new Pool({
      host: process.env.DB_HOST,
      port: process.env.DB_PORT,
