        rejectUnauthorized: true
      } : false
    });

    // Handle pool errors
    this.pool.on('error', (err, client) => {
      console.error('Unexpected error on idle client:', err);
      // Don't exit - the pool will handle reconnection
    });

    // Handle pool connection events
    this.pool.on('connect', () => {
      console.log('New client connected to pool');
    });

    this.pool.on('remove', () => {
      console.log('Client removed from pool');
    });

    return this;
  }

  // Execute a query with timeout and error handling
  async query(text, params, options = {}) {
    const timeout = options.timeout || 15000;

    // Create a timeout promise
    const timeoutPromise = new Promise((_, reject) => {
      setTimeout(() => {
        reject(new Error(`Query timeout after ${timeout}ms`));
      }, timeout);
    });

    try {
      // Race between query and timeout
      const result = await Promise.race([
        this.pool.query(text, params),
        timeoutPromise
      ]);

      return {
        success: true,
        data: result.rows,
        rowCount: result.rowCount,
        fields: result.fields
      };
    } catch (error) {
      console.error('Query error:', {
        query: text,
        params,
        error: error.message
      });

      return {
        success: false,
        error: error.message,
        code: error.code,
        detail: error.detail
      };
    }
  }

  // Get a client from the pool for transactions
  async getClient() {
    if (this.isShuttingDown) {
      throw new Error('Database is shutting down');
    }

    const client = await this.pool.connect();
    const originalQuery = client.query.bind(client);
    const originalRelease = client.release.bind(client);

    // Set timeout for the client
    let isTimeoutEnabled = false;
    let timeoutId = null;

    // Override release to clear timeout
    client.release = () => {
      if (timeoutId) {
        clearTimeout(timeoutId);
        timeoutId = null;
      };
      return originalRelease();
    };

    // Add timeout method
    client.setQueryTimeout = (ms) => {
      isTimeoutEnabled = true;
      timeoutId = setTimeout(() => {
        client.query('SELECT pg_cancel_backend(pid) FROM pg_stat_activity WHERE pid = pg_backend_pid()')
          .then(() => {
            client.release();
          })
          .catch(() => {
            client.release();
          });
      }, ms);
    };

    return client;
  }

  // Execute transaction with automatic commit/rollback
  async transaction(callback) {
    const client = await this.getClient();

    try {
      await client.query('BEGIN');
      const result = await callback(client);
      await client.query('COMMIT');
      return result;
    } catch (error) {
      await client.query('ROLLBACK');
      throw error;
    } finally {
      client.release();
    }
  }

  // Health check
  async healthCheck() {
    try {
      const result = await this.pool.query('SELECT 1');
      return { healthy: true, latency: Date.now() };
    } catch (error) {
      return { healthy: false, error: error.message };
    }
  }

  // Graceful shutdown
  async shutdown() {
    this.isShuttingDown = true;

    try {
      await this.pool.end();
      console.log('Database pool has been closed');
    } catch (error) {
      console.error('Error closing database pool:', error);
      throw error;
    }
  }

  // Get pool stats
  getStats() {
    return {
      total: this.pool.totalCount,
      idle: this.pool.idleCount,
      waiting: this.pool.waitingCount
    };
  }
}

// Create singleton instance
