  console.error('Unexpected client error:', err.message);
});

// Query with timeout wrapper
async function queryWithTimeout(text, params, timeoutMs = 5000) {
  const client = await pool.connect();
  try {
    const result = await Promise.race([
      client.query(text, params),
      new Promise((_, reject) =>
        setTimeout(() => reject(new Error('Query timeout')), timeoutMs)
      )
    ]);
    return result;
  } finally {
    client.release();
  }
}

// Usage
const res = await queryWithTimeout('SELECT * FROM users WHERE id = $1', [userId]);
```

**Key configs:**

| Param | What it does |
|-------|--------------|
| `max` | Cap connections. Match DB `max_connections` setting |
| `idleTimeoutMillis` | Release unused connections. Prevents connection leaks |
| `connectionTimeoutMillis` | Fail fast on network issues |
| `statement_timeout` | Server-side query timeout. Returns error 0x000571 |
| `query_timeout` (via promise race) | Client-side timeout. Cancellable |

**Shutdown graceful:**

```js
process.on('SIGTERM', async () => {
  await pool.end();  // wait for active queries
  process.exit(0);
});
```

**Gotchas:**
- Always `release()` in `finally` — else connection leaks
- Pool `error` event: client-level errors (connection dies mid-query)
- Query rejection ≠ connection death. Pool handles reconnect automatically

Need pooling for serverless? Use `pg-pooling` or `pgBouncer` in front.

