# PostgreSQL Connection Pool in Node.js

Use `pg` library's `Pool` class. Here's proper config:

```javascript
import { Pool } from 'pg'

const pool = new Pool({
  max: 20,                    // max connections (default: 10)
  idleTimeoutMillis: 30000,   // close idle after 30s
  connectionTimeoutMillis: 5000, // fail fast if no connection in 5s
  // Optional: per-connection settings
  statement_timeout: 30000,   // query timeout in ms (0 = disabled)
  // ssl: { rejectUnauthorized: false }  // for prod cert validation
})

// Error handling - catches pool-level errors
pool.on('error', (err, client) => {
  console.error('Unexpected pool error:', err.message)
  // Client already returned to pool
})

// Helper wrapper
export async function query(text, params) {
  const start = Date.now()
  try {
    const res = await pool.query(text, params)
    const duration = Date.now() - start
    console.log('Query executed', { text, duration, rows: res.rowCount })
    return res
  } catch (err) {
    console.error('Query failed:', { text, error: err.message })
    throw err
  }
}

export async function getClient() {
  const client = await pool.connect()
  const originalQuery = client.query.bind(client)
  const release = client.release.bind(client)

  // Track query count to detect leaks
  client.query = (...args) => {
    client.queryCount = (client.queryCount || 0) + 1
    return originalQuery(...args)
  }

  client.release = (force = false) => {
    if (client.queryCount === 0 || force) {
      client.queryCount = 0
      return release(force)
    }
    console.warn('Client released with', client.queryCount, 'unreleased queries')
    return release(force)
  }

  return client
}

// Graceful shutdown - call on process exit
export async function closePool() {
  await pool.end()
  console.log('Pool closed')
}
```

## Timeout Hierarchy

| Setting | Purpose |
|---------|---------|
| `connectionTimeoutMillis` | Wait time to acquire connection from pool |
| `idleTimeoutMillis` | Close idle connections sitting in pool |
| `statement_timeout` | Max query execution time (server-side) |

## Common Issues

**Pool exhausted**: `max` too low or clients not released. Always use `try/finally` with manual clients:

```javascript
const client = await pool.connect()
try {
  // work
} finally {
  client.release()  // returns to pool
}
```

**Connection refused**: `connectionTimeoutMillis` will throw after timeout. Catch at app level:

```javascript
try {
  await pool.query('SELECT 1')
} catch (err) {
  if (err.code === 'ETIMEDOUT' || err.code === 'ECONNREFUSED') {
    // reconnect logic
  }
}
```

**Query timeout**: `statement_timeout` aborts long queries server-side. Returns `57014` error code.

## Production Checklist

- Set `max` to `num_cores - 1` for CPU-bound, ~`num_cores * 2` for I/O-bound
- Enable SSL in production (`ssl: { rejectUnauthorized: true }`)
- Monitor `pool.totalCount` and `pool.idleCount` via metrics
- Call `pool.end()` on SIGTERM/SIGINT for graceful shutdown

Use `pg` library. Pool manages connections efficiently, handles reconnection.

## Basic Setup

```js
const { Pool } = require('pg');

const pool = new Pool({
  host: process.env.DB_HOST,
  port: process.env.DB_PORT || 5432,
  database: process.env.DB_NAME,
  user: process.env.DB_USER,
  password: process.env.DB_PASS,

  // Pool sizing
  max: 20,              // max connections
  idleTimeoutMillis: 30000,    // close idle after 30s
  connectionTimeoutMillis: 2000, // fail fast if no connection available

  // Statement timeout (per-query, ms)
  statement_timeout: 30000,
});
```

## Timeout Configuration

```js
// Three distinct timeouts:
connectionTimeoutMillis  // acquire connection from pool
idleTimeoutMillis        // release idle connections
statement_timeout        // abort long-running queries

// Custom per-query timeout helper
const queryWithTimeout = async (text, params, timeoutMs = 5000) => {
  const client = await pool.connect();
  try {
    await client.query(`SET statement_timeout = ${timeoutMs}`);
    return await client.query(text, params);
  } finally {
    await client.query('RESET statement_timeout');
    client.release();
  }
};
```

## Error Handling

```js
pool.on('error', (err, client) => {
  // Unhandled errors on idle clients
  console.error('Unexpected pool error:', err.message);
  // Don't release - pool auto-removes broken client
});

pool.on('connect', (client) => {
  // Log new connections for debugging
  console.log('New client:', client.processID);
});

// Query wrapper with retry
const queryWithRetry = async (text, params, retries = 3) => {
  for (let i = 0; i < retries; i++) {
    try {
      return await pool.query(text, params);
    } catch (err) {
      if (err.code === 'ECONNREFUSED' || err.code === 'ETIMEDOUT') {
        await new Promise(r => setTimeout(r, 1000 * (i + 1)));
        continue;
      }
      throw err;
    }
  }
  throw new Error(`Query failed after ${retries} retries`);
};
```

## Graceful Shutdown

```js
process.on('SIGTERM', async () => {
  console.log('SIGTERM received, closing pool...');
  await pool.end();  // wait for active queries
  process.exit(0);
});
```

## Connection Check

```js
// Health check endpoint
app.get('/health', async (req, res) => {
  try {
    const result = await pool.query('SELECT 1');
    const state = pool.totalCount + '/' + pool.max;
    res.json({ status: 'ok', connections: state });
  } catch (err) {
    res.status(503).json({ status: 'error', message: err.message });
  }
});
```

## Key Points

| Setting | Value | Purpose |
|---------|-------|---------|
| `max` | CPU cores × 2-4 | Tune to DB `max_connections` limit |
| `idleTimeoutMillis` | 30-60s | Prevent connection staleness |
| `connectionTimeoutMillis` | 2-5s | Fail fast, trigger retry logic |
| `statement_timeout` | match SLA | Prevent runaway queries |

Pool auto-recycles broken connections. `pool.query()` handles `release()` internally. Use `pool.connect()` only when you need transaction control.

Use `pg` (node-postgres). Pool reuse connections automatically.

```js
import { Pool } from 'pg';

const pool = new Pool({
  max: 20,              // max clients in pool
  idleTimeoutMillis: 30000,  // close idle after 30s
  connectionTimeoutMillis: 2000,  // fail fast if no available conn
});

// Log + handle pool errors
pool.on('error', (err, client) => {
  console.error('Unexpected pool error:', err.message);
  // Don't close pool here - let it recover
});

pool.on('connect', () => {
  console.log('New client connected. Pool size:', pool.totalCount);
});

// Helper: auto-release, timeout, error handling
export async function query(text, params, timeoutMs = 5000) {
  const controller = new AbortController();
  const timeout = setTimeout(() => controller.abort(), timeoutMs);

  try {
    const result = await pool.query(text, params, {
      signal: controller.signal,
    });
    return result;
  } catch (err) {
    if (err.name === 'AbortError') {
      throw new Error(`Query timeout after ${timeoutMs}ms: ${text}`);
    }
    throw err;
  } finally {
    clearTimeout(timeout);
  }
}

// Graceful shutdown - call on process signals
export async function closePool() {
  await pool.end();
  console.log('Pool closed');
}
```

**Usage:**

```js
// Basic query
const { rows } = await query('SELECT * FROM users WHERE id = $1', [userId]);

// Transaction helper
export async function transaction(fn) {
  const client = await pool.connect();
  try {
    await client.query('BEGIN');
    const result = await fn(client);
    await client.query('COMMIT');
    return result;
  } catch (err) {
    await client.query('ROLLBACK');
    throw err;
  } finally {
    client.release();
  }
}
```

**Key configs explained:**

| Setting | Value | Why |
|---------|-------|-----|
| `max` | CPU cores × 2 (or ~20) | Balance memory vs concurrency |
| `connectionTimeoutMillis` | 2-5s | Fail fast, don't wait forever |
| `idleTimeoutMillis` | 30-60s | Free resources from low-traffic periods |

**Process signal handler:**

```js
process.on('SIGTERM', async () => {
  console.log('SIGTERM received, closing pool...');
  await closePool();
  process.exit(0);
});
```

Pool automatically queues requests when all 20 clients busy. Won't reject - just waits. Set `statement_timeout` server-side if you need per-query limits beyond client timeouts.

