# Refactored Async/Await Version

Here's the refactored function using async/await:

```javascript
async function getUser(id) {
  const rows = await db.query('SELECT * FROM users WHERE id = ?', [id]);

  if (!rows.length) {
    throw new Error('Not found');
  }

  return rows[0];
}
```

## Usage

```javascript
// With try/catch
async function main() {
  try {
    const user = await getUser(123);
    console.log(user);
  } catch (err) {
    console.error(err.message); // 'Not found' or database error
  }
}

// Or destructure with .catch()
const user = await getUser(123).catch(err => ({ error: err.message }));
```

## Important Note

This assumes you're using a **promise-based** database driver. If you're using `mysql` or `mysql2`, enable the promise API:

```javascript
// mysql2 example
const mysql = require('mysql2/promise');
const db = mysql.createPool({ host: 'localhost', database: 'mydb' });

// If using callback-based mysql with callbacks, wrap it:
function getUser(id) {
  return new Promise((resolve, reject) => {
    db.query('SELECT * FROM users WHERE id = ?', [id], (err, rows) => {
      if (err) return reject(err);
      if (!rows.length) return reject(new Error('Not found'));
      resolve(rows[0]);
    });
  });
}
```

## Key Changes

| Callback Version | Async/Await Version |
|------------------|---------------------|
| Callback parameter | Return value |
| `callback(err)` | `throw err` |
| `callback(null, data)` | `return data` |
| Nested error handling | Try/catch blocks |
| Pyramid of doom | Flat, linear code |

# Refactored to Async/Await

## Solution

```javascript
function getUser(id) {
  return new Promise((resolve, reject) => {
    db.query('SELECT * FROM users WHERE id = ?', [id], (err, rows) => {
      if (err) return reject(err);
      if (!rows.length) return reject(new Error('Not found'));
      resolve(rows[0]);
    });
  });
}

// Usage
async function main() {
  try {
    const user = await getUser(123);
    console.log(user);
  } catch (err) {
    console.error(err.message);
  }
}
```

## Key Changes

| Before (Callback) | After (Async/Await) |
|-------------------|---------------------|
| `callback(err)` | `reject(err)` |
| `callback(null, data)` | `resolve(data)` |
| Nested error handling | `try/catch` blocks |

## Even Cleaner with `util.promisify`

If your database driver supports it, you can eliminate the manual Promise wrapper:

```javascript
const { promisify } = require('util');
const query = promisify(db.query).bind(db);

async function getUser(id) {
  const rows = await query('SELECT * FROM users WHERE id = ?', [id]);
  if (!rows.length) throw new Error('Not found');
  return rows[0];
}
```

> **Note:** If you're using `mysql2` with `.promise()`, you can call `db.query()` directly with `await` without any wrapper.

# Refactored to Async/Await

Here's the refactored version with a promise wrapper for the callback-based `db.query`:

```javascript
// Promisified version
function getUser(id) {
  return new Promise((resolve, reject) => {
    db.query('SELECT * FROM users WHERE id = ?', [id], (err, rows) => {
      if (err) return reject(err);
      if (!rows.length) return reject(new Error('Not found'));
      resolve(rows[0]);
    });
  });
}

// Usage with async/await
async function getUserById(id) {
  const rows = await getUser(id);
  return rows[0];
}
```

## Cleaner Single-Function Approach

```javascript
async function getUser(id) {
  const rows = await new Promise((resolve, reject) => {
    db.query('SELECT * FROM users WHERE id = ?', [id], (err, rows) => {
      if (err) return reject(err);
      resolve(rows);
    });
  });

  if (!rows.length) {
    throw new Error('Not found');
  }

  return rows[0];
}
```

## Usage Example

```javascript
// Caller side
async function main() {
  try {
    const user = await getUser(123);
    console.log(user);
  } catch (err) {
    if (err.message === 'Not found') {
      console.log('User does not exist');
    } else {
      console.error('Database error:', err);
    }
  }
}

main();
```

